class Solution:
    def canConvertString(self, s: str, t: str, k: int) -> bool:
        if len(s) != len(t):
            return False

        diff_count = [0] * 26
        for a, b in zip(s, t):
            diff = (ord(b) - ord(a)) % 26
            if diff != 0:
                diff_count[diff] += 1

        for i, count in enumerate(diff_count):
            if count > 0:
                required_moves = i + 26 * (count - 1)
                if required_moves > k:
                    return False

        return True
```

